final:
module RefModule (
  input clk,
  input reset,
  input shift_in,
  output reg [3:0] q
);

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
    if (reset)
      q <= 4'b0000;
    else
      q <= {q[2:0], shift_in};
  end

endmodule
